import { NextResponse } from 'next/server';

// =====================================================
// D-ID ICE Candidate relay
// Sends browser ICE candidates to D-ID for WebRTC negotiation
// =====================================================

const DID_BASE = 'https://api.d-id.com';

function getAuthHeader(): string {
    const key = process.env.DID_API_KEY;
    if (!key) throw new Error('DID_API_KEY not set');
    return `Basic ${key}`;
}

export const dynamic = 'force-dynamic';

export async function POST(request: Request) {
    try {
        const { streamId, sessionId, candidate } = await request.json();

        if (!streamId || !sessionId || candidate === undefined) {
            return NextResponse.json(
                { error: 'Missing streamId, sessionId, or candidate' },
                { status: 400 }
            );
        }

        const res = await fetch(`${DID_BASE}/talks/streams/${streamId}/ice`, {
            method: 'POST',
            headers: {
                Authorization: getAuthHeader(),
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                candidate,
                session_id: sessionId,
            }),
        });

        if (!res.ok) {
            const err = await res.text();
            console.error('D-ID ICE error:', err);
            return NextResponse.json({ error: 'ICE relay failed', detail: err }, { status: 500 });
        }

        return NextResponse.json({ ok: true });
    } catch (error) {
        return NextResponse.json({ error: 'ICE route error' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';

// =====================================================
// D-ID SDP Exchange — WebRTC negotiation
// After browser creates its SDP answer, send it to D-ID
// =====================================================

const DID_BASE = 'https://api.d-id.com';

function getAuthHeader(): string {
    const key = process.env.DID_API_KEY;
    if (!key) throw new Error('DID_API_KEY not set');
    return `Basic ${key}`;
}

export const dynamic = 'force-dynamic';

export async function POST(request: Request) {
    try {
        const { streamId, sessionId, answer } = await request.json();

        if (!streamId || !sessionId || !answer) {
            return NextResponse.json(
                { error: 'Missing streamId, sessionId, or answer' },
                { status: 400 }
            );
        }

        const res = await fetch(`${DID_BASE}/talks/streams/${streamId}/sdp`, {
            method: 'POST',
            headers: {
                Authorization: getAuthHeader(),
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                answer,
                session_id: sessionId,
            }),
        });

        if (!res.ok) {
            const err = await res.text();
            console.error('D-ID SDP error:', err);
            return NextResponse.json({ error: 'SDP exchange failed', detail: err }, { status: 500 });
        }

        return NextResponse.json({ ok: true });
    } catch (error) {
        return NextResponse.json({ error: 'SDP route error' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';

// =====================================================
// D-ID Speak — Sends text to the avatar to say
// The avatar lip-syncs using ElevenLabs TTS internally
// OR using D-ID's built-in TTS as fallback
// =====================================================

const DID_BASE = 'https://api.d-id.com';

// ElevenLabs voice ID for Rachel (professional female voice)
const ELEVENLABS_VOICE_ID =
    process.env.ELEVENLABS_VOICE_ID || '21m00Tcm4TlvDq8ikWAM';

function getAuthHeader(): string {
    const key = process.env.DID_API_KEY;
    if (!key) throw new Error('DID_API_KEY not set');
    return `Basic ${key}`;
}

export const dynamic = 'force-dynamic';

export async function POST(request: Request) {
    try {
        const { streamId, sessionId, text } = await request.json();

        if (!streamId || !sessionId || !text) {
            return NextResponse.json(
                { error: 'Missing streamId, sessionId, or text' },
                { status: 400 }
            );
        }

        // Build script config — prefer ElevenLabs if key is available
        const elevenLabsKey = process.env.ELEVENLABS_API_KEY;

        const provider = elevenLabsKey
            ? {
                type: 'elevenlabs' as const,
                voice_id: ELEVENLABS_VOICE_ID,
                api_key: elevenLabsKey,
                model_id: 'eleven_multilingual_v2',
                voice_settings: {
                    stability: 0.5,
                    similarity_boost: 0.75,
                    style: 0.3,
                    use_speaker_boost: true,
                },
            }
            : {
                type: 'microsoft' as const,
                voice_id: 'en-US-JennyNeural',
            };

        const res = await fetch(`${DID_BASE}/talks/streams/${streamId}/clips`, {
            method: 'POST',
            headers: {
                Authorization: getAuthHeader(),
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                script: {
                    type: 'text',
                    input: text,
                    provider,
                },
                config: {
                    fluent: true,
                    pad_audio: 0.0,
                    stitch: true,
                },
                session_id: sessionId,
                background: {
                    color: '#0f1014', // Match our dark surface color
                },
            }),
        });

        if (!res.ok) {
            const err = await res.text();
            console.error('D-ID speak error:', err);
            return NextResponse.json({ error: 'Speak failed', detail: err }, { status: 500 });
        }

        const data = await res.json();
        return NextResponse.json(data);
    } catch (error) {
        return NextResponse.json({ error: 'Speak route error' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';

// =====================================================
// D-ID Streaming API — Create & manage avatar streams
// Docs: https://docs.d-id.com/reference/createstream
//
// Auth: D-ID says to send the key DIRECTLY as:
//   Authorization: Basic <YOUR KEY>
//   No additional base64 encoding — the key from the studio
//   is already in the correct format.
//
// Image requirements:
//   - Publicly reachable URL (D-ID servers must be able to GET it)
//   - Contains a clear frontal face
//   - JPEG or PNG, ideally 400x400+
// =====================================================

const DID_BASE = 'https://api.d-id.com';

function getAuthHeader(): string {
    const key = process.env.DID_API_KEY;
    if (!key) throw new Error('DID_API_KEY not set');
    // D-ID docs: Authorization: Basic <YOUR KEY> — use directly, no re-encoding
    return `Basic ${key}`;
}

// ── POST /api/avatar/stream ────────────────────────────────────
export async function POST() {
    try {
        const auth = getAuthHeader();

        // randomuser.me is consistently accessible by external servers and contains real faces
        // Override via DID_PRESENTER_URL in .env.local with any publicly reachable image URL
        const PRESENTER_URL =
            process.env.DID_PRESENTER_URL ||
            'https://randomuser.me/api/portraits/women/44.jpg';

        const res = await fetch(`${DID_BASE}/talks/streams`, {
            method: 'POST',
            headers: {
                Authorization: auth,
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                // Use D-ID's built-in clip presenter — no external image URL needed
                // Override presenter via DID_PRESENTER_ID env var
                presenter_type: 'clip',
                presenter_id: process.env.DID_PRESENTER_ID || 'amy-Aq6OmGZnMt',
                driver_id: 'mXra4jY38i',
                config: {
                    stitch: true,
                    result_format: 'mp4',
                },
            }),
        });

        if (!res.ok) {
            const err = await res.text();
            console.error('D-ID create stream error:', res.status, err);
            return NextResponse.json(
                { error: 'Failed to create stream', detail: err, httpStatus: res.status },
                { status: res.status }
            );
        }

        const data = await res.json();
        return NextResponse.json(data);
    } catch (error) {
        console.error('D-ID stream route error:', error);
        return NextResponse.json(
            { error: error instanceof Error ? error.message : 'Unknown error' },
            { status: 500 }
        );
    }
}

// ── DELETE /api/avatar/stream ──────────────────────────────────
export async function DELETE(request: Request) {
    try {
        const { streamId } = await request.json();
        if (!streamId) return NextResponse.json({ error: 'Missing streamId' }, { status: 400 });

        await fetch(`${DID_BASE}/talks/streams/${streamId}`, {
            method: 'DELETE',
            headers: { Authorization: getAuthHeader() },
        });

        return NextResponse.json({ ok: true });
    } catch {
        return NextResponse.json({ error: 'Failed to close stream' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import OpenAI from 'openai';

// =====================================================
// Streaming LLM endpoint
// Returns server-sent events so the frontend can
// show text progressively as the interviewer speaks
// =====================================================

let _openai: OpenAI | null = null;
function getOpenAI(): OpenAI {
    if (!_openai) {
        if (!process.env.OPENAI_API_KEY) {
            throw new Error('OPENAI_API_KEY not set');
        }
        _openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
    }
    return _openai;
}

const SYSTEM_PROMPT = `You are an expert technical interviewer at a top tech company.
You conduct fair, challenging interviews and speak naturally like a real person.
Keep responses concise — 1-3 sentences unless giving detailed feedback.
Ask one thing at a time.`;

export const dynamic = 'force-dynamic';

export async function POST(request: Request) {
    try {
        const { config, messages, problem, code, action } = await request.json();

        const contextMessages: OpenAI.Chat.ChatCompletionMessageParam[] = [
            { role: 'system', content: SYSTEM_PROMPT },
        ];

        const constraintsText = problem?.constraints?.length
            ? problem.constraints.map((c: string) => `• ${c}`).join('\n')
            : 'Not specified';

        const examplesText = problem?.examples?.length
            ? problem.examples
                .map((e: any, i: number) => `Example ${i + 1}: Input = ${e.input} → Output = ${e.output}`)
                .join('\n')
            : 'None provided';

        // Extract last candidate message
        const lastCandidateMsg = Array.isArray(messages) && messages.length > 0
            ? [...messages].reverse().find((m) => m.role === 'candidate' || m.role === 'user')?.content ?? ''
            : '';

        // Build the advanced intent-classification prompt
        const promptText = `You are interviewing a candidate for a ${config?.role || 'software engineering'} position.

== PROBLEM ==
Title: ${problem?.title || 'General discussion'}
Description: ${problem?.description || 'N/A'}
Constraints:
${constraintsText}
Examples:
${examplesText}

${code ? `== CANDIDATE'S CODE (${config?.language || 'code'}) ==\n\`\`\`${config?.language}\n${code}\n\`\`\`` : '(No code submitted yet)'}

== CANDIDATE'S LAST MESSAGE ==
"${lastCandidateMsg}"

---
STEP 1 — Classify the candidate's last message into ONE intent:
• clarification_request — asking about constraints, input format, edge cases, assumptions, or expected output
• thinking_aloud — narrating their thoughts, not asking for anything specific
• approach_proposed — proposing a specific algorithm or data structure to solve the problem
• partial_answer — describing an approach but not fully done
• complete_answer — submitted code or fully explained a complete solution
• needs_hint — clearly stuck, says they don't know or asks for help
• off_topic — unrelated to the problem

STEP 2 — Formulate your response:
• If clarification_request → Answer the question DIRECTLY using the problem info above. Be concise and helpful. Do NOT pivot to a follow-up question yet.
• If thinking_aloud → Encourage briefly (1-2 sentences) ("Good instinct", "Keep going"). Do NOT ask a follow-up.
• If approach_proposed → EVALUATE the pre-coding checklist by reading the ENTIRE conversation history. Have they completed ALL 4 of the following: 1) restated the problem, 2) asked about edge cases/constraints, 3) discussed AT LEAST 2 different approaches (or trade-offs), and 4) stated time & space complexity of their chosen approach? 
  - If NO (missing any step): Acknowledge their approach, but ask them to complete ONE missing step (e.g. "That approach makes sense. Before we code, can you think of any alternative approaches?" or "What are the time/space complexities?").
  - If YES to all 4: Explicitly give them the go-ahead to start coding. Do NOT ask endless follow-up questions if the approach is sound.
• If partial_answer → Ask ONE targeted follow-up about their specific approach, a complexity concern, or an edge case they haven't mentioned.
• If complete_answer → Give brief feedback. Then, check the ENTIRE conversation history. Have they discussed time/space complexity? Have they discussed edge cases? Ask ONE question about a topic they have NOT YET discussed. If they have already discussed BOTH complexity AND edge cases in the past, do NOT ask about them again. Instead, just formally wrap up the interview.
• If needs_hint → Give ONE small directional hint using a guiding question. Never reveal the solution.
• If off_topic → Gently redirect to the problem.

CRITICAL RULES:
- MENTAL CHECKLIST: Before allowing the candidate to code, you MUST mentally verify they have done ALL 4: 1. Restated problem, 2. Asked about edge cases, 3. Discussed >1 approach, 4. Stated time/space complexity. Do not blindly say "go ahead" if they skipped even one of these.
- AVOID REPETITION: Never ask a question about time complexity, space complexity, or edge cases if the candidate has ALREADY answered it previously in the conversation. Read the history carefully!
- IMPORTANT: DO NOT speak your classified intent aloud. NEVER prefix your response with "needs_hint", "clarification_request", etc.
- Just provide the conversational response as if you were speaking directly to the candidate.
- Never ignore a clarification question. Always answer it first.
- Ask at most ONE question per turn.
- Keep responses concise — 2-4 sentences max.
- Sound like a human, not a chatbot. Use natural conversation flow.`;

        // We only pass the system prompt and conversation history to the LLM
        // The instructions above serve as the final system message guiding its behavior
        contextMessages.push({
            role: 'system',
            content: promptText,
        });

        // Add the specific action instructions if it's evaluated code or wrap_up
        if (action === 'evaluate_code') {
            contextMessages.push({
                role: 'system',
                content: 'Special instruction: The candidate just submitted code. Evaluate it briefly, mention edge cases, and ask about time/space complexity.',
            });
        } else if (action === 'wrap_up') {
            contextMessages.push({
                role: 'system',
                content: 'Special instruction: The interview time is up. Wrap up professionally and tell the candidate you are done.',
            });
        } else if (code && code.trim() !== '') {
            contextMessages.push({
                role: 'system',
                content: 'Special instruction: The candidate has started coding. Do NOT rapid-fire questions at them. Allow them to code in silence unless they ask a question, think aloud, or you notice a critical flaw. If you must ask a question, ask ONE reasonable question about their choice of data structure or an edge case, then let them continue working.',
            });
        }


        // Create streaming response
        const stream = await getOpenAI().chat.completions.create({
            model: 'gpt-4o',
            messages: contextMessages,
            stream: true,
            temperature: 0.7,
            max_tokens: 300,
        });

        // Return as a ReadableStream with SSE format
        const encoder = new TextEncoder();
        const readable = new ReadableStream({
            async start(controller) {
                try {
                    for await (const chunk of stream) {
                        const delta = chunk.choices[0]?.delta?.content;
                        if (delta) {
                            controller.enqueue(
                                encoder.encode(`data: ${JSON.stringify({ text: delta })}\n\n`)
                            );
                        }
                    }
                    controller.enqueue(encoder.encode('data: [DONE]\n\n'));
                } catch (err) {
                    controller.error(err);
                } finally {
                    controller.close();
                }
            },
        });

        return new Response(readable, {
            headers: {
                'Content-Type': 'text/event-stream',
                'Cache-Control': 'no-cache',
                Connection: 'keep-alive',
            },
        });
    } catch (error) {
        console.error('Streaming LLM error:', error);
        return NextResponse.json({ error: 'Stream failed' }, { status: 500 });
    }
}

'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { useBehavioralStore } from '@/stores/behavioral-store';
import { useSpeechInput } from '@/hooks/useSpeechInput';
import { useTTS } from '@/hooks/useTTS';
import type {
    BehavioralMessage,
    BehavioralFeedback,
    BehavioralChecklistItem,
} from '@/types/behavioral';
import { v4 as uuidv4 } from 'uuid';

// =====================================================
// Behavioral Interview Session Page
// Full-width chat with voice input — no code editor
// =====================================================



export default function BehavioralSessionPage() {
    const router = useRouter();
    const {
        session,
        feedback,
        setPhase,
        addMessage,
        setFeedback,
        endSession,
    } = useBehavioralStore();

    const [isThinking, setIsThinking] = useState(false);
    const [isSpeaking, setIsSpeaking] = useState(false);
    const [candidateInput, setCandidateInput] = useState('');
    const [elapsedSeconds, setElapsedSeconds] = useState(0);

    const { speak } = useTTS({
        onStart: () => setIsSpeaking(true),
        onEnd: () => setIsSpeaking(false),
    });

    const chatEndRef = useRef<HTMLDivElement>(null);
    const hasStarted = useRef(false);

    // ── Voice input ──
    const {
        isListening,
        isSupported: speechSupported,
        interimTranscript,
        toggleListening,
    } = useSpeechInput({
        onStop: (fullTranscript) => {
            if (fullTranscript.trim()) {
                handleSend(fullTranscript.trim());
            }
        },
    });

    // Space to toggle mic (not in inputs)
    useEffect(() => {
        const handler = (e: KeyboardEvent) => {
            if (e.code !== 'Space' || !speechSupported) return;
            const active = document.activeElement as HTMLElement | null;
            if (
                !active ||
                active.tagName.toLowerCase() === 'input' ||
                active.tagName.toLowerCase() === 'textarea' ||
                active.isContentEditable
            ) return;
            e.preventDefault();
            toggleListening();
        };
        window.addEventListener('keydown', handler);
        return () => window.removeEventListener('keydown', handler);
    }, [speechSupported, toggleListening]);

    // ── Redirect if no session ──
    useEffect(() => {
        if (!session) {
            router.push('/behavioral/setup');
        }
    }, [session, router]);

    // ── Timer ──
    useEffect(() => {
        if (!session || session.phase === 'debrief') return;
        const timer = setInterval(() => {
            setElapsedSeconds(Math.floor((Date.now() - session.startedAt) / 1000));
        }, 1000);
        return () => clearInterval(timer);
    }, [session]);

    // ── Auto-scroll ──
    useEffect(() => {
        chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [session?.messages, isThinking]);

    // ── Helpers ──
    const formatTime = (secs: number) => {
        const m = Math.floor(secs / 60);
        const s = secs % 60;
        return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const callAPI = useCallback(
        async (url: string, body: object) => {
            try {
                const res = await fetch(url, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(body),
                });
                return await res.json();
            } catch (err) {
                console.error(`API call failed: ${url}`, err);
                return null;
            }
        },
        []
    );

    const interviewerSay = useCallback(
        async (text: string, type: BehavioralMessage['type']) => {
            const msg: BehavioralMessage = {
                id: uuidv4(),
                role: 'interviewer',
                content: text,
                timestamp: Date.now(),
                type,
            };
            addMessage(msg);
            await speak(text);
        },
        [addMessage, speak]
    );

    // Stream response from behavioral API
    const streamResponse = useCallback(
        async (action: string, extraMsg?: BehavioralMessage): Promise<string> => {
            if (!session) return '';

            const allMessages = extraMsg
                ? [...session.messages, extraMsg]
                : session.messages;

            const res = await fetch('/api/behavioral/stream', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    config: session.config,
                    messages: allMessages,
                    action,
                }),
            });

            if (!res.ok || !res.body) return '';

            const reader = res.body.getReader();
            const decoder = new TextDecoder();
            let fullText = '';

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                const chunk = decoder.decode(value, { stream: true });
                for (const line of chunk.split('\n')) {
                    if (line.startsWith('data: ')) {
                        const data = line.slice(6);
                        if (data === '[DONE]') break;
                        try {
                            const { text } = JSON.parse(data);
                            if (text) fullText += text;
                        } catch { }
                    }
                }
            }

            return fullText.trim();
        },
        [session]
    );

    // ── Start interview ──
    useEffect(() => {
        if (!session || hasStarted.current) return;
        hasStarted.current = true;

        (async () => {
            setIsThinking(true);

            // 1. Greeting
            const greetingData = await callAPI('/api/behavioral/greeting', {
                config: session.config,
            });
            if (greetingData?.greeting) {
                await interviewerSay(greetingData.greeting, 'greeting');
            }

            // 2. First question
            setPhase('questioning');
            const firstQ = await streamResponse('first_question');
            if (firstQ) {
                await interviewerSay(firstQ, 'question');
            }

            setIsThinking(false);
        })();
    }, [session, callAPI, interviewerSay, setPhase, streamResponse]);

    // ── Handle candidate message ──
    const handleSend = async (text?: string) => {
        const content = (text || candidateInput).trim();
        if (!content || !session) return;

        const candidateMsg: BehavioralMessage = {
            id: uuidv4(),
            role: 'candidate',
            content,
            timestamp: Date.now(),
            type: 'answer',
        };
        addMessage(candidateMsg);

        setCandidateInput('');
        setIsThinking(true);

        const response = await streamResponse('follow_up', candidateMsg);
        if (response) {
            await interviewerSay(response, 'follow_up');
        }

        setIsThinking(false);
    };

    // ── End interview ──
    const handleEndInterview = async () => {
        if (!session) return;

        setIsThinking(true);

        // Wrap-up message
        const wrapUp = await streamResponse('wrap_up');
        if (wrapUp) {
            await interviewerSay(wrapUp, 'feedback');
        }

        endSession();

        // Generate feedback
        const feedbackData = await callAPI('/api/behavioral/feedback', {
            config: session.config,
            messages: session.messages,
        });

        if (feedbackData) {
            setFeedback({ sessionId: session.id, ...feedbackData });
            // Fire-and-forget save to Supabase
            fetch('/api/sessions/behavioral', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    session: { ...session, phase: 'debrief', endedAt: Date.now() },
                    feedback: { ...feedbackData, sessionId: session.id },
                }),
            }).catch(console.error);
        }

        setIsThinking(false);
    };

    if (!session) return null;

    const modeLabel =
        session.config.mode === 'resume_grill'
            ? '🔬 Resume Grill'
            : session.config.mode === 'behavioral'
                ? '💬 Behavioral'
                : '🔀 Mixed';

    const totalSeconds = session.config.durationMinutes * 60;
    const timeLeft = totalSeconds - elapsedSeconds;
    const isOvertime = timeLeft < 0;

    // ═══════════════════════════════════════
    // DEBRIEF VIEW
    // ═══════════════════════════════════════
    if (session.phase === 'debrief' && feedback) {
        const ScoreCard = ({ label, score }: { label: string; score: number }) => (
            <div className="card p-4 text-center flex flex-col items-center justify-center gap-2 border border-[oklch(1_0_0/0.05)] bg-[oklch(0.12_0.02_260)]">
                <span className="text-[10px] text-[oklch(0.5_0.01_260)] uppercase tracking-wider font-semibold">{label}</span>
                <span className="text-3xl font-bold text-[oklch(0.8_0.01_260)]">
                    {score}<span className="text-lg text-[oklch(0.3_0.01_260)]">/5</span>
                </span>
            </div>
        );

        const CheckItem = ({ label, item }: { label: string; item: BehavioralChecklistItem }) => (
            <li className="space-y-1">
                <div className="flex items-start gap-3 text-sm">
                    <div className={`mt-0.5 shrink-0 w-4 h-4 rounded-full flex items-center justify-center border ${item.passed ? 'bg-[oklch(0.6_0.15_150)] border-[oklch(0.6_0.15_150)] text-black' : 'border-[oklch(0.3_0.02_260)] text-transparent'}`}>
                        <svg viewBox="0 0 14 14" fill="none" className="w-2.5 h-2.5" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                            <polyline points="3 7.5 6 10.5 11 3.5" />
                        </svg>
                    </div>
                    <span className={item.passed ? 'text-[oklch(0.7_0.01_260)]' : 'text-[oklch(0.4_0.01_260)] line-through'}>
                        {label}
                    </span>
                </div>
                {item.passed && item.evidence && (
                    <p className="ml-7 text-[10px] text-[oklch(0.55_0.05_250)] italic leading-snug border-l-2 border-[oklch(0.55_0.05_250/0.4)] pl-2">
                        &quot;{item.evidence}&quot;
                    </p>
                )}
            </li>
        );

        const decisionColor =
            feedback.decision === 'Strong Hire'
                ? 'oklch(0.72_0.17_165)'
                : feedback.decision === 'Hire'
                    ? 'oklch(0.72_0.17_165)'
                    : 'oklch(0.63_0.22_25)';

        const isResumeMode = session.config.mode !== 'behavioral';

        return (
            <main className="min-h-screen flex flex-col overflow-y-auto">
                <nav className="glass-strong fixed top-0 inset-x-0 z-50 px-6 py-4">
                    <div className="max-w-7xl mx-auto flex items-center justify-between">
                        <Link href="/" className="flex items-center gap-2">
                            <span className="text-2xl">🤖</span>
                            <span className="font-[var(--font-display)] text-xl font-bold gradient-text">
                                InterviewerAI
                            </span>
                        </Link>
                        <span className="text-sm text-[oklch(0.5_0.01_260)]">
                            Behavioral Debrief
                        </span>
                    </div>
                </nav>

                <div className="flex-1 max-w-5xl mx-auto w-full px-6 pt-28 pb-16 space-y-8">
                    {/* Header */}
                    <div className="text-center space-y-4">
                        <h1 className="font-[var(--font-display)] text-3xl sm:text-4xl font-bold">
                            Interview <span className="gradient-text">Complete</span>
                        </h1>
                        <div className="flex items-center justify-center gap-4 flex-wrap">
                            <span className="px-3 py-1 rounded-full text-xs font-semibold" style={{ backgroundColor: `color-mix(in oklch, ${decisionColor}, transparent 85%)`, color: decisionColor }}>
                                {feedback.decision}
                            </span>
                            <span className="text-4xl font-bold text-[oklch(0.85_0.01_260)]">
                                {feedback.overallScore}<span className="text-xl text-[oklch(0.3_0.01_260)]">/10</span>
                            </span>
                        </div>
                    </div>

                    {/* Scores */}
                    <div className="grid grid-cols-5 gap-3">
                        <ScoreCard label="Communication" score={feedback.scores.communication} />
                        <ScoreCard label="Storytelling" score={feedback.scores.storytelling} />
                        <ScoreCard label="Technical Depth" score={feedback.scores.technicalDepth} />
                        <ScoreCard label="Self-Awareness" score={feedback.scores.selfAwareness} />
                        <ScoreCard label="Leadership" score={feedback.scores.leadershipTeamwork} />
                    </div>

                    <div className="grid md:grid-cols-3 gap-6 items-start">
                        {/* Report */}
                        <div className="md:col-span-2 card p-6 bg-[oklch(0.12_0.02_260)]/50">
                            <h2 className="font-[var(--font-display)] font-semibold text-lg mb-4 text-[oklch(0.8_0.01_260)] flex items-center gap-2">
                                <span className="text-xl">📝</span> Interviewer Report
                            </h2>
                            <div className="text-[oklch(0.7_0.01_260)] leading-relaxed whitespace-pre-wrap text-sm font-sans">
                                {feedback.report}
                            </div>
                        </div>

                        {/* Checklists */}
                        <div className="space-y-4">
                            {/* Answer Quality */}
                            <div className="card p-5 bg-[oklch(0.12_0.02_260)]/50">
                                <h3 className="font-[var(--font-display)] font-semibold text-xs uppercase tracking-wider mb-4 text-[oklch(0.6_0.05_250)]">
                                    Answer Quality
                                </h3>
                                <ul className="space-y-3">
                                    <CheckItem label="Gave specific examples" item={feedback.checklists.answerQuality.gaveSpecificExamples} />
                                    <CheckItem label="Used STAR structure" item={feedback.checklists.answerQuality.usedSTARStructure} />
                                    <CheckItem label="Quantified impact" item={feedback.checklists.answerQuality.quantifiedImpact} />
                                    <CheckItem label="Showed ownership" item={feedback.checklists.answerQuality.showedOwnership} />
                                    <CheckItem label="Addressed follow-ups" item={feedback.checklists.answerQuality.addressedFollowUps} />
                                </ul>
                            </div>

                            {/* Resume Depth (only for resume/mixed modes) */}
                            {isResumeMode && (
                                <div className="card p-5 bg-[oklch(0.12_0.02_260)]/50">
                                    <h3 className="font-[var(--font-display)] font-semibold text-xs uppercase tracking-wider mb-4 text-[oklch(0.6_0.05_250)]">
                                        Resume Depth
                                    </h3>
                                    <ul className="space-y-3">
                                        <CheckItem label="Technical accuracy" item={feedback.checklists.resumeDepth.technicalAccuracy} />
                                        <CheckItem label="Depth of understanding" item={feedback.checklists.resumeDepth.depthOfUnderstanding} />
                                    </ul>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="flex gap-4 justify-center pt-8 border-t border-[oklch(1_0_0/0.05)]">
                        <Link href="/behavioral/setup" className="btn-primary">
                            Practice Again
                        </Link>
                        <Link href="/" className="btn-secondary">
                            Back Home
                        </Link>
                    </div>
                </div>
            </main>
        );
    }

    // ═══════════════════════════════════════
    // INTERVIEW SESSION VIEW
    // ═══════════════════════════════════════
    return (
        <main className="min-h-screen flex flex-col">
            {/* Nav */}
            <nav className="glass-strong fixed top-0 inset-x-0 z-50 px-4 py-3">
                <div className="max-w-7xl mx-auto flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <Link href="/" className="flex items-center gap-2">
                            <span className="text-xl">🤖</span>
                            <span className="font-[var(--font-display)] text-lg font-bold gradient-text hidden sm:inline">
                                InterviewerAI
                            </span>
                        </Link>
                        <span className="text-xs px-2 py-0.5 rounded bg-[oklch(0.22_0.02_260)] text-[oklch(0.72_0.17_165)]">
                            {modeLabel}
                        </span>
                    </div>
                    <div className="flex items-center gap-4">
                        {/* Timer */}
                        <span className={`font-mono text-sm ${isOvertime ? 'text-[oklch(0.63_0.22_25)]' : timeLeft < 120 ? 'text-[oklch(0.75_0.18_85)]' : 'text-[oklch(0.5_0.01_260)]'}`}>
                            {isOvertime ? `+${formatTime(Math.abs(timeLeft))}` : formatTime(timeLeft)}
                        </span>
                        <button
                            onClick={handleEndInterview}
                            disabled={isThinking}
                            className="text-xs px-3 py-1.5 rounded-lg bg-[oklch(0.22_0.08_25/0.3)] text-[oklch(0.75_0.18_25)] border border-[oklch(0.75_0.18_25/0.3)] hover:bg-[oklch(0.22_0.08_25/0.5)] transition-all disabled:opacity-40"
                        >
                            End Interview
                        </button>
                    </div>
                </div>
            </nav>

            {/* Chat Area */}
            <div className="flex-1 flex flex-col pt-16 max-w-3xl mx-auto w-full">
                {/* Messages */}
                <div className="flex-1 overflow-y-auto px-4 py-4 space-y-4">
                    {session.messages.map((msg) => (
                        <div
                            key={msg.id}
                            className={`flex ${msg.role === 'candidate' ? 'justify-end' : 'justify-start'}`}
                        >
                            <div
                                className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${msg.role === 'interviewer'
                                    ? 'bg-[oklch(0.18_0.02_260)] border border-[oklch(1_0_0/0.06)] text-[oklch(0.82_0.01_260)]'
                                    : 'bg-[oklch(0.35_0.12_250)] text-white'
                                    }`}
                            >
                                {msg.content}
                            </div>
                        </div>
                    ))}

                    {/* Thinking indicator */}
                    {isThinking && (
                        <div className="flex justify-start">
                            <div className="bg-[oklch(0.18_0.02_260)] border border-[oklch(1_0_0/0.06)] rounded-2xl px-4 py-3">
                                <div className="flex gap-1.5">
                                    <span className="w-2 h-2 rounded-full bg-[oklch(0.4_0.01_260)] animate-bounce" style={{ animationDelay: '0ms' }} />
                                    <span className="w-2 h-2 rounded-full bg-[oklch(0.4_0.01_260)] animate-bounce" style={{ animationDelay: '150ms' }} />
                                    <span className="w-2 h-2 rounded-full bg-[oklch(0.4_0.01_260)] animate-bounce" style={{ animationDelay: '300ms' }} />
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Speaking indicator */}
                    {isSpeaking && !isThinking && (
                        <div className="flex justify-start">
                            <div className="text-[10px] text-[oklch(0.4_0.01_260)] flex items-center gap-2 px-2">
                                <span className="animate-pulse">🔊</span> Speaking...
                            </div>
                        </div>
                    )}

                    <div ref={chatEndRef} />
                </div>

                {/* Input Area */}
                <div className="px-4 py-3 border-t border-[oklch(1_0_0/0.06)] space-y-2">
                    {/* Voice recording overlay */}
                    {isListening ? (
                        <div className="flex items-center gap-3">
                            {speechSupported && (
                                <button
                                    onClick={toggleListening}
                                    className="shrink-0 w-10 h-10 rounded-xl flex items-center justify-center transition-all bg-[oklch(0.63_0.22_25)] animate-pulse"
                                    title="Stop recording (Space)"
                                >
                                    ⏹
                                </button>
                            )}
                            <div className="flex-1 min-h-[40px] rounded-xl bg-[oklch(0.18_0.02_260)] border border-[oklch(0.63_0.22_25/0.5)] px-4 py-2 flex items-center">
                                <span className="text-sm text-[oklch(0.75_0.01_260)] italic leading-snug">
                                    {interimTranscript
                                        ? `"${interimTranscript}…"`
                                        : <span className="text-[oklch(0.4_0.01_260)]">Listening… speak now</span>
                                    }
                                </span>
                            </div>
                            <span className="text-[10px] text-[oklch(0.35_0.01_260)] shrink-0">Space<br />to stop</span>
                        </div>
                    ) : (
                        <div className="flex gap-2">
                            {speechSupported && (
                                <button
                                    onClick={toggleListening}
                                    className="shrink-0 w-10 h-10 rounded-xl flex items-center justify-center transition-all bg-[oklch(0.22_0.02_260)] hover:bg-[oklch(0.28_0.02_260)]"
                                    title="Start speaking (Space)"
                                >
                                    🎙
                                </button>
                            )}
                            <input
                                type="text"
                                value={candidateInput}
                                onChange={(e) => setCandidateInput(e.target.value)}
                                onKeyDown={(e) =>
                                    e.key === 'Enter' && !e.shiftKey && handleSend()
                                }
                                placeholder="Type a response, or press Space to speak…"
                                className="input-field flex-1 py-2 text-sm"
                            />
                            <button
                                onClick={() => handleSend()}
                                disabled={!candidateInput.trim() || isThinking}
                                className="btn-primary px-4 py-2 text-sm shrink-0 disabled:opacity-40"
                            >
                                Send
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </main>
    );
}

'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { createSupabaseBrowserClient } from '@/lib/supabase';
import type { User } from '@supabase/supabase-js';

// =====================================================
// Interview History Dashboard
// Shows only the current user's sessions via RLS
// =====================================================

interface SessionRow {
    id: string;
    type: 'technical' | 'behavioral';
    config: Record<string, unknown>;
    started_at: string;
    ended_at: string | null;
    duration_secs: number | null;
    created_at: string;
    feedback: {
        overall_score: number;
        decision: string;
        scores: Record<string, number>;
    } | null;
}

function formatDuration(secs: number | null) {
    if (!secs) return '—';
    const m = Math.floor(secs / 60);
    const s = secs % 60;
    return `${m}m ${s}s`;
}

function formatDate(iso: string) {
    return new Date(iso).toLocaleDateString('en-US', {
        month: 'short', day: 'numeric', year: 'numeric',
        hour: '2-digit', minute: '2-digit',
    });
}

const DECISION_COLOR: Record<string, string> = {
    'Strong Hire': 'oklch(0.72_0.17_165)',
    'Hire': 'oklch(0.65_0.14_165)',
    'No Hire': 'oklch(0.63_0.22_25)',
};

export default function DashboardPage() {
    const [sessions, setSessions] = useState<SessionRow[]>([]);
    const [user, setUser] = useState<User | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const supabase = createSupabaseBrowserClient();

    useEffect(() => {
        async function load() {
            const { data: { user } } = await supabase.auth.getUser();
            setUser(user);

            if (!user) {
                setIsLoading(false);
                return;
            }

            const { data, error } = await supabase
                .from('sessions')
                .select(`*, feedback (overall_score, decision, scores)`)
                .eq('user_id', user.id)
                .order('created_at', { ascending: false })
                .limit(50);

            if (error) setError('Failed to load sessions.');
            else setSessions((data as SessionRow[]) ?? []);
            setIsLoading(false);
        }
        load();
    }, [supabase]);

    const handleSignOut = async () => {
        await supabase.auth.signOut();
        window.location.href = '/login';
    };

    // Stats
    const total = sessions.length;
    const technical = sessions.filter((s) => s.type === 'technical').length;
    const behavioral = sessions.filter((s) => s.type === 'behavioral').length;
    const hires = sessions.filter((s) =>
        s.feedback?.decision === 'Hire' || s.feedback?.decision === 'Strong Hire'
    ).length;
    const avgScore = sessions.length
        ? (sessions.reduce((sum, s) => sum + (s.feedback?.overall_score ?? 0), 0) / sessions.length).toFixed(1)
        : '—';

    return (
        <main className="min-h-screen flex flex-col">
            <div className="flex-1 max-w-5xl mx-auto w-full px-6 pt-8 pb-16 space-y-8">
                <div>
                    <h1 className="font-[var(--font-display)] text-3xl font-bold mb-1">
                        Interview <span className="gradient-text">History</span>
                    </h1>
                    {user && (
                        <p className="text-[oklch(0.5_0.01_260)] text-sm">{user.email}</p>
                    )}
                </div>

                {/* Stats row */}
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                    {[
                        { label: 'Total Sessions', value: total },
                        { label: 'Technical', value: technical },
                        { label: 'Behavioral', value: behavioral },
                        { label: 'Avg Score', value: total ? `${avgScore}/10` : '—' },
                    ].map((stat) => (
                        <div key={stat.label} className="card p-4 text-center">
                            <div className="text-2xl font-bold gradient-text">{stat.value}</div>
                            <div className="text-[10px] uppercase tracking-wider text-[oklch(0.5_0.01_260)] mt-1">{stat.label}</div>
                        </div>
                    ))}
                </div>

                {/* Session list */}
                {isLoading ? (
                    <div className="text-center py-24 text-[oklch(0.4_0.01_260)]">
                        <span className="animate-spin inline-block text-3xl mb-4">⏳</span>
                        <p>Loading sessions…</p>
                    </div>
                ) : error ? (
                    <div className="card p-8 text-center text-[oklch(0.63_0.22_25)]">⚠ {error}</div>
                ) : sessions.length === 0 ? (
                    <div className="card p-16 text-center space-y-4">
                        <div className="text-5xl">🎤</div>
                        <h2 className="font-[var(--font-display)] text-xl font-semibold">No sessions yet</h2>
                        <p className="text-[oklch(0.5_0.01_260)] text-sm">Complete an interview and it&apos;ll show up here.</p>
                        <Link href="/interview/setup" className="btn-primary inline-block">Start an Interview</Link>
                    </div>
                ) : (
                    <div className="space-y-3">
                        {sessions.map((s) => {
                            const decision = s.feedback?.decision;
                            const color = decision ? DECISION_COLOR[decision] : 'oklch(0.4_0.01_260)';
                            const cfg = s.config as { mode?: string; difficulty?: string; role?: string; company?: string };

                            return (
                                <Link key={s.id} href={`/dashboard/${s.id}`} className="card p-5 flex items-center gap-5 hover:border-[oklch(1_0_0/0.15)] transition-all cursor-pointer">
                                    <div className="shrink-0 text-2xl">{s.type === 'technical' ? '💻' : '🗣️'}</div>
                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-center gap-2 flex-wrap">
                                            <span className="font-semibold text-[oklch(0.8_0.01_260)] text-sm capitalize">
                                                {s.type === 'technical' ? 'Technical' : `Behavioral — ${cfg.mode?.replace('_', ' ')}`}
                                            </span>
                                            {cfg.role && <span className="text-[10px] px-2 py-0.5 rounded bg-[oklch(0.22_0.02_260)] text-[oklch(0.55_0.01_260)]">{cfg.role}</span>}
                                            {cfg.company && <span className="text-[10px] px-2 py-0.5 rounded bg-[oklch(0.22_0.02_260)] text-[oklch(0.55_0.01_260)]">@ {cfg.company}</span>}
                                        </div>
                                        <div className="text-xs text-[oklch(0.4_0.01_260)] mt-1">
                                            {formatDate(s.created_at)} · {formatDuration(s.duration_secs)}
                                            {cfg.difficulty && ` · ${cfg.difficulty}`}
                                        </div>
                                    </div>
                                    {s.feedback && (
                                        <div className="shrink-0 text-right">
                                            <div className="text-xl font-bold text-[oklch(0.8_0.01_260)]">
                                                {s.feedback.overall_score}<span className="text-sm text-[oklch(0.4_0.01_260)]">/10</span>
                                            </div>
                                            <div className="text-[10px] font-semibold mt-0.5" style={{ color }}>{decision}</div>
                                        </div>
                                    )}
                                    <div className="shrink-0 text-[oklch(0.3_0.01_260)]">→</div>
                                </Link>
                            );
                        })}
                    </div>
                )}

                {total > 0 && (
                    <p className="text-center text-xs text-[oklch(0.35_0.01_260)]">
                        {hires} of {total} sessions with Hire or Strong Hire decision
                    </p>
                )}
            </div>
        </main>
    );
}

'use client';

import { useCallback, useEffect, useRef, useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useInterviewStore } from '@/stores/interview-store';
import { useTTS } from '@/hooks/useTTS';
import { useSpeechInput } from '@/hooks/useSpeechInput';
import { useDIDAvatar } from '@/hooks/useDIDAvatar';
import type { Message } from '@/types/interview';
import { v4 as uuidv4 } from 'uuid';

// Use standard import instead of next/dynamic to avoid Vercel edge/lambda compilation issues
import MonacoEditor from '@monaco-editor/react';

const LANG_MONACO: Record<string, string> = {
    python: 'python',
    javascript: 'javascript',
    typescript: 'typescript',
    java: 'java',
    cpp: 'cpp',
    go: 'go',
};

//  Avatar Component (Animated gradient  no D-ID) 
function AvatarPanel({ isSpeaking, isThinking }: { isSpeaking: boolean; isThinking: boolean }) {
    return (
        <div className="flex flex-col items-center gap-4 py-6 px-4 border-b border-[oklch(1_0_0/0.06)]">
            <div className="relative">
                {isSpeaking && (
                    <>
                        <div className="absolute -inset-3 rounded-full border-2 border-[oklch(0.55_0.18_250/0.4)] animate-ping" style={{ animationDuration: '1.8s' }} />
                        <div className="absolute -inset-5 rounded-full border border-[oklch(0.55_0.18_250/0.15)] animate-ping" style={{ animationDuration: '1.8s', animationDelay: '0.6s' }} />
                    </>
                )}
                <div
                    className={`w-24 h-24 rounded-full relative shadow-2xl transition-all duration-500 ${isSpeaking ? 'shadow-[0_0_30px_oklch(0.55_0.18_250/0.5)]' : ''}`}
                    style={{
                        background: isSpeaking
                            ? 'conic-gradient(from 0deg, oklch(0.55 0.18 250), oklch(0.48 0.2 280), oklch(0.62 0.15 230), oklch(0.55 0.18 250))'
                            : 'conic-gradient(from 180deg, oklch(0.35 0.08 260), oklch(0.28 0.06 240), oklch(0.38 0.09 270), oklch(0.35 0.08 260))',
                    }}
                >
                    <div className="absolute inset-1 rounded-full bg-[oklch(0.15_0.03_260)] flex flex-col items-center justify-center gap-0.5">
                        <span className="text-2xl font-bold font-[var(--font-display)] text-white">AI</span>
                        <span className="text-[8px] font-medium text-[oklch(0.6_0.08_250)] tracking-widest uppercase">Alex</span>
                    </div>
                    {isSpeaking && (
                        <div className="absolute -inset-0.5 rounded-full animate-spin" style={{ background: 'conic-gradient(from 0deg, transparent 60%, oklch(0.72 0.17 165), transparent)', animationDuration: '3s' }} />
                    )}
                </div>
                <div className={`absolute bottom-1 right-1 w-4 h-4 rounded-full border-2 border-[oklch(0.15_0.03_260)] ${isSpeaking ? 'bg-[oklch(0.72_0.17_165)]' : isThinking ? 'bg-[oklch(0.75_0.18_85)] animate-pulse' : 'bg-[oklch(0.45_0.01_260)]'}`} />
            </div>

            <div className="text-center space-y-1.5">
                <div className="font-[var(--font-display)] font-semibold text-sm tracking-wide">Alex &mdash; AI Interviewer</div>
                {isSpeaking ? (
                    <div className="flex items-center justify-center gap-0.5 h-4">
                        {[0.4, 0.8, 1, 0.6, 0.9, 0.5, 0.7].map((h, i) => (
                            <div key={i} className="w-0.5 rounded-full bg-[oklch(0.55_0.18_250)] animate-pulse"
                                style={{ height: `${h * 100}%`, animationDelay: `${i * 0.12}s`, animationDuration: '0.8s' }} />
                        ))}
                    </div>
                ) : (
                    <div className="text-xs text-[oklch(0.5_0.01_260)]">
                        {isThinking ? 'Thinking...' : 'Listening'}
                    </div>
                )}
            </div>
        </div>
    );
}



//  Run Result Component 
interface RunResult {
    success: boolean;
    output: string;
    error?: string;
    executionTime?: string;
    statusDescription: string;
}

function RunResultPanel({ result }: { result: RunResult | null }) {
    if (!result) return null;
    return (
        <div
            className={`mx-3 mb-2 rounded-lg p-3 text-xs font-mono border ${result.success
                ? 'bg-[oklch(0.15_0.05_145/0.3)] border-[oklch(0.72_0.17_165/0.3)]'
                : 'bg-[oklch(0.15_0.05_25/0.3)] border-[oklch(0.63_0.22_25/0.3)]'
                }`}
        >
            <div className="flex items-center justify-between mb-1.5">
                <span
                    className={
                        result.success
                            ? 'text-[oklch(0.72_0.17_165)]'
                            : 'text-[oklch(0.63_0.22_25)]'
                    }
                >
                    {result.success ? '' : ''} {result.statusDescription}
                </span>
                {result.executionTime && (
                    <span className="text-[oklch(0.5_0.01_260)]">
                        ⏱ {result.executionTime}s
                    </span>
                )}
            </div>
            {result.output && (
                <pre className="text-[oklch(0.80_0.01_260)] whitespace-pre-wrap">
                    {result.output}
                </pre>
            )}
            {result.error && (
                <pre className="text-[oklch(0.70_0.15_25)] whitespace-pre-wrap">
                    {result.error}
                </pre>
            )}
        </div>
    );
}

//  Main Session Page 


export default function InterviewSessionPage() {
    const router = useRouter();
    const session = useInterviewStore((s) => s.session);
    const feedback = useInterviewStore((s) => s.feedback);
    const setPhase = useInterviewStore((s) => s.setPhase);
    const addMessage = useInterviewStore((s) => s.addMessage);
    const setProblem = useInterviewStore((s) => s.setProblem);
    const setFeedback = useInterviewStore((s) => s.setFeedback);
    const endSession = useInterviewStore((s) => s.endSession);

    const [code, setCode] = useState('');
    const [typedProblem, setTypedProblem] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const [isThinking, setIsThinking] = useState(false);
    const [isSpeaking, setIsSpeaking] = useState(false);
    const [candidateInput, setCandidateInput] = useState('');
    const [elapsedSeconds, setElapsedSeconds] = useState(0);
    const [runResult, setRunResult] = useState<RunResult | null>(null);
    const [isRunning, setIsRunning] = useState(false);
    const [streamingText, setStreamingText] = useState('');
    const [isRequestingHint, setIsRequestingHint] = useState(false);

    const { speak, stop: stopSpeaking } = useTTS({
        onStart: () => setIsSpeaking(true),
        onEnd: () => setIsSpeaking(false),
    });

    const chatEndRef = useRef<HTMLDivElement>(null);
    const hasStarted = useRef(false);

    // D-ID avatar (disabled by default unless DID_ENABLED=true in .env.local)
    const avatar = useDIDAvatar({
        onStatusChange: (s) => {
            if (s === 'speaking') setIsSpeaking(true);
            else if (s === 'connected') setIsSpeaking(false);
        },
    });


    const {
        isListening,
        isSupported: speechSupported,
        interimTranscript,
        toggleListening,
    } = useSpeechInput({
        onStop: (fullTranscript) => {
            // When user stops mic (Ctrl+Space or button), auto-send everything they said
            if (fullTranscript.trim()) {
                handleSend(fullTranscript.trim());
            }
        },
    });

    // Ctrl+Space toggles the mic
    useEffect(() => {
        const handler = (e: KeyboardEvent) => {
            if (e.code !== 'Space' || !speechSupported) return;
            const active = document.activeElement as HTMLElement | null;
            // Never intercept Space when focus is inside an input, textarea,
            // or anywhere inside the Monaco editor
            if (
                !active ||
                active.tagName.toLowerCase() === 'input' ||
                active.tagName.toLowerCase() === 'textarea' ||
                active.isContentEditable ||
                active.closest('.monaco-editor')
            ) return;
            e.preventDefault();
            toggleListening();
        };
        window.addEventListener('keydown', handler);
        return () => window.removeEventListener('keydown', handler);
    }, [speechSupported, toggleListening]);

    // Redirect if no session
    useEffect(() => {
        if (!session) {
            router.push('/interview/setup');
        }
    }, [session, router]);

    // Auto-connect D-ID avatar when session is available
    useEffect(() => {
        if (!session) return;
        (async () => {
            try {
                const res = await fetch('/api/avatar/available');
                const { available } = await res.json();
                if (available) {
                    avatar.connect();
                }
            } catch {
                // D-ID not configured  silently skip
            }
        })();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [session?.id]);


    // Timer
    useEffect(() => {
        if (!session || session.phase === 'debrief') return;
        const timer = setInterval(() => setElapsedSeconds((p) => p + 1), 1000);
        return () => clearInterval(timer);
    }, [session]);

    // Warn when approaching limit
    const timeLimit = (session?.config.durationMinutes || 30) * 60;
    const timeWarning =
        elapsedSeconds > 0 &&
        elapsedSeconds >= timeLimit - 120 &&
        elapsedSeconds < timeLimit;

    // Auto-scroll
    useEffect(() => {
        chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [session?.messages, streamingText]);

    //  Typewriter 
    const typeText = useCallback((text: string, onComplete?: () => void) => {
        setIsTyping(true);
        setTypedProblem('');
        let i = 0;
        const interval = setInterval(() => {
            if (i < text.length) {
                const char = text[i]; // capture by value before i increments
                i++;
                setTypedProblem((prev) => prev + char);
            } else {
                clearInterval(interval);
                setIsTyping(false);
                onComplete?.();
            }
        }, 20);
        return () => clearInterval(interval);
    }, []);

    //  Streaming LLM response 
    const streamResponse = useCallback(
        async (
            action: string,
            extraCode?: string,
            newMessage?: Message // Optional fresh message to append during this render cycle
        ): Promise<string> => {
            if (!session) return '';

            setStreamingText('');
            let fullText = '';

            // Construct up-to-date messages array
            const currentMessages = [...session.messages];
            if (newMessage) {
                currentMessages.push(newMessage);
            }

            try {
                const res = await fetch('/api/interview/stream', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        config: session.config,
                        messages: currentMessages,
                        problem: session.currentProblem,
                        code: extraCode || code,
                        action,
                    }),
                });

                if (!res.ok || !res.body) {
                    throw new Error('Stream failed');
                }

                const reader = res.body.getReader();
                const dec = new TextDecoder();

                while (true) {
                    const { done, value } = await reader.read();
                    if (done) break;

                    const chunk = dec.decode(value);
                    const lines = chunk.split('\n');
                    for (const line of lines) {
                        if (line.startsWith('data: ')) {
                            const data = line.slice(6);
                            if (data === '[DONE]') break;
                            try {
                                const { text } = JSON.parse(data);
                                if (text) {
                                    fullText += text;
                                    setStreamingText(fullText);
                                }
                            } catch {
                                // ignore parse errors
                            }
                        }
                    }
                }
            } catch (err) {
                console.error('Streaming error:', err);
            }

            setStreamingText('');
            return fullText;
        },
        [session, code]
    );

    //  API helper 
    const callAPI = useCallback(async (endpoint: string, body: object) => {
        try {
            const res = await fetch(endpoint, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
            });
            if (!res.ok) return null;
            return await res.json();
        } catch {
            return null;
        }
    }, []);

    //  Speak and add message — awaits TTS completion so callers can sequence messages 
    const interviewerSay = useCallback(
        async (content: string, type: Message['type'] = 'question') => {
            addMessage({ role: 'interviewer', content, type });
            if (avatar.isConnected) {
                avatar.speak(content);
            } else {
                await speak(content); // speak() now resolves when audio ENDS
            }
        },
        [addMessage, speak, avatar]
    );


    //  Request a hint 
    const handleHint = async () => {
        if (!session || isRequestingHint) return;
        setIsRequestingHint(true);
        setIsThinking(true);

        const hintMsg: Message = {
            id: uuidv4(),
            role: 'candidate',
            content: 'Can I get a hint?',
            timestamp: Date.now(),
            type: 'answer'
        };
        addMessage(hintMsg);

        const response = await streamResponse('hint', undefined, hintMsg);
        if (response) {
            await interviewerSay(response, 'hint');
        }

        setIsThinking(false);
        setIsRequestingHint(false);
    };

    //  Start interview — sequential, waits for each TTS to finish before next 
    useEffect(() => {
        if (!session || hasStarted.current) return;
        hasStarted.current = true;

        (async () => {
            setIsThinking(true);

            // 1. Brief greeting
            const greetingData = await callAPI('/api/interview/greeting', {
                config: session.config,
            });
            if (greetingData?.greeting) {
                await interviewerSay(greetingData.greeting, 'greeting');
            }

            // 2. Generate and present the problem
            setPhase('questioning');
            const problemData = await callAPI('/api/interview/problem', {
                config: session.config,
            });

            if (problemData?.problem) {
                const prob = problemData.problem;
                setProblem(prob);
                setPhase('code_share');

                const starterCode = prob.starterCode?.[session.config.language] || '';
                setCode(starterCode);

                // Type out the problem, then prompt the candidate
                typeText(prob.description, async () => {
                    setPhase('candidate_coding');
                    await interviewerSay(
                        "Take your time to read through the problem. Feel free to ask me any clarifying questions before you start.",
                        'question'
                    );
                });
            }

            setIsThinking(false);
        })();
    }, [session, callAPI, interviewerSay, setPhase, setProblem, typeText]);


    //  Handle candidate message 
    const handleSend = async (text?: string) => {
        const content = (text || candidateInput).trim();
        if (!content || !session) return;

        const candidateMsg: Message = {
            id: uuidv4(),
            role: 'candidate',
            content,
            timestamp: Date.now(),
            type: 'answer'
        };
        addMessage(candidateMsg);

        setCandidateInput('');
        setIsThinking(true);

        const response = await streamResponse('follow_up', undefined, candidateMsg);
        if (response) {
            await interviewerSay(response, 'follow_up');
        }

        setIsThinking(false);
    };

    //  Handle code submission 
    const handleSubmitCode = async () => {
        if (!session || !code.trim()) return;

        const candidateMsg: Message = {
            id: uuidv4(),
            role: 'candidate',
            content: `I've completed my solution.`,
            timestamp: Date.now(),
            type: 'answer',
        };
        addMessage(candidateMsg);

        setPhase('follow_up');
        setIsThinking(true);

        const response = await streamResponse('evaluate_code', code, candidateMsg);
        if (response) {
            await interviewerSay(response, 'follow_up');
        }

        setIsThinking(false);
    };

    //  Run code 
    const handleRunCode = async () => {
        if (!session || !code.trim()) return;
        setIsRunning(true);
        setRunResult(null);

        const result = await callAPI('/api/code/run', {
            code,
            language: session.config.language,
        });

        setRunResult(result);
        setIsRunning(false);
    };

    //  End interview 
    const handleEndInterview = async () => {
        if (!session) return;
        stopSpeaking();
        endSession();
        setIsThinking(true);

        const feedbackData = await callAPI('/api/interview/feedback', {
            config: session.config,
            messages: session.messages,
            code,
        });

        if (feedbackData) {
            setFeedback({ sessionId: session.id, ...feedbackData });
            // Fire-and-forget save to Supabase
            fetch('/api/sessions/technical', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    session: { ...session, phase: 'debrief', endedAt: Date.now() },
                    feedback: { ...feedbackData, sessionId: session.id },
                }),
            }).catch(console.error);
        }

        setIsThinking(false);
    };

    const formatTime = (secs: number) => {
        const m = Math.floor(secs / 60);
        const s = secs % 60;
        return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    if (!session) return null;

    // """""""""""""""""""""""""""""""""""""""""""""""
    // DEBRIEF VIEW
    // """""""""""""""""""""""""""""""""""""""""""""""
    if (session.phase === 'debrief' && feedback) {
        const ScoreCard = ({ label, score }: { label: string; score: number }) => (
            <div className="card p-4 text-center flex flex-col items-center justify-center gap-2 border border-[oklch(1_0_0/0.05)] bg-[oklch(0.12_0.02_260)]">
                <span className="text-[10px] text-[oklch(0.5_0.01_260)] uppercase tracking-wider font-semibold">{label}</span>
                <span className="text-3xl font-bold text-[oklch(0.8_0.01_260)]">
                    {score}<span className="text-lg text-[oklch(0.3_0.01_260)]">/5</span>
                </span>
            </div>
        );

        const ChecklistItem = ({ label, item }: { label: string; item: import('@/types/interview').ChecklistItem }) => (
            <li className="space-y-1">
                <div className="flex items-start gap-3 text-sm">
                    <div className={`mt-0.5 shrink-0 w-4 h-4 rounded-full flex items-center justify-center border ${item.passed ? 'bg-[oklch(0.6_0.15_150)] border-[oklch(0.6_0.15_150)] text-black' : 'border-[oklch(0.3_0.02_260)] text-transparent'}`}>
                        <svg viewBox="0 0 14 14" fill="none" className="w-2.5 h-2.5" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                            <polyline points="3 7.5 6 10.5 11 3.5" />
                        </svg>
                    </div>
                    <span className={item.passed ? 'text-[oklch(0.7_0.01_260)]' : 'text-[oklch(0.4_0.01_260)] line-through'}>
                        {label}
                    </span>
                </div>
                {item.passed && item.evidence && (
                    <p className="ml-7 text-[10px] text-[oklch(0.55_0.05_250)] italic leading-snug border-l-2 border-[oklch(0.55_0.05_250/0.4)] pl-2">
                        "{item.evidence}"
                    </p>
                )}
            </li>
        );

        return (
            <main className="min-h-screen flex flex-col overflow-y-auto">
                <nav className="glass-strong fixed top-0 inset-x-0 z-50 px-6 py-4">
                    <div className="max-w-7xl mx-auto flex items-center justify-between">
                        <Link href="/" className="flex items-center gap-2">
                            <span className="text-2xl">🤖</span>
                            <span className="font-[var(--font-display)] text-xl font-bold gradient-text">
                                InterviewerAI
                            </span>
                        </Link>
                    </div>
                </nav>

                <div className="flex-1 flex flex-col items-center px-6 pt-28 pb-16">
                    <div className="w-full max-w-5xl space-y-8">
                        {/* Header: Score & Decision */}
                        <div className="text-center mb-10">
                            <h1 className="font-[var(--font-display)] text-4xl font-bold mb-4">
                                Decision:{' '}
                                <span className={
                                    feedback.decision === 'Strong Hire' ? 'text-[oklch(0.72_0.17_165)]' :
                                        feedback.decision === 'Hire' ? 'text-[oklch(0.7_0.1_250)]' :
                                            'text-[oklch(0.65_0.2_25)]'
                                }>
                                    {feedback.decision}
                                </span>
                            </h1>
                            <div className="flex items-center justify-center gap-2">
                                <span className="text-6xl font-bold gradient-text">
                                    {feedback.overallScore}
                                </span>
                                <span className="text-[oklch(0.4_0.01_260)] text-2xl font-medium">/ 10</span>
                            </div>
                            <p className="text-sm text-[oklch(0.5_0.01_260)] mt-3">
                                Interview Duration: {formatTime(elapsedSeconds)}
                            </p>
                        </div>

                        {/* 1-5 Scores Grid */}
                        <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
                            <ScoreCard label="Problem Solving" score={feedback.scores.problemSolving} />
                            <ScoreCard label="DSA Knowledge" score={feedback.scores.dsa} />
                            <ScoreCard label="Communication" score={feedback.scores.communication} />
                            <ScoreCard label="Coding Skills" score={feedback.scores.coding} />
                            <ScoreCard label="Speed" score={feedback.scores.speed} />
                        </div>

                        <div className="grid md:grid-cols-3 gap-6 items-start">
                            {/* Detailed Report (Takes up 2 columns) */}
                            <div className="md:col-span-2 card p-6 bg-[oklch(0.12_0.02_260)]/50">
                                <h2 className="font-[var(--font-display)] font-semibold text-lg mb-4 text-[oklch(0.8_0.01_260)] flex items-center gap-2">
                                    <span className="text-xl">📝</span> Interviewer Report
                                </h2>
                                <div className="text-[oklch(0.7_0.01_260)] leading-relaxed whitespace-pre-wrap text-sm font-sans">
                                    {feedback.report}
                                </div>
                            </div>

                            {/* Checklists (Takes up 1 column, stacked) */}
                            <div className="space-y-4">
                                {/* Before Coding */}
                                <div className="card p-5 bg-[oklch(0.12_0.02_260)]/50">
                                    <h3 className="font-[var(--font-display)] font-semibold text-xs uppercase tracking-wider mb-4 text-[oklch(0.6_0.05_250)]">
                                        Before Coding
                                    </h3>
                                    <ul className="space-y-3">
                                        <ChecklistItem label="Restated the problem" item={feedback.checklists.beforeCoding.restatedProblem} />
                                        <ChecklistItem label="Asked about constraints/edge cases" item={feedback.checklists.beforeCoding.askedClarifyingQuestions} />
                                        <ChecklistItem label="Discussed at least 2 approaches" item={feedback.checklists.beforeCoding.discussedApproaches} />
                                        <ChecklistItem label="Stated time/space complexity" item={feedback.checklists.beforeCoding.statedComplexity} />
                                        <ChecklistItem label="Got go-ahead before coding" item={feedback.checklists.beforeCoding.gotGoAhead} />
                                    </ul>
                                </div>

                                {/* During Coding */}
                                <div className="card p-5 bg-[oklch(0.12_0.02_260)]/50">
                                    <h3 className="font-[var(--font-display)] font-semibold text-xs uppercase tracking-wider mb-4 text-[oklch(0.6_0.05_250)]">
                                        During Coding
                                    </h3>
                                    <ul className="space-y-3">
                                        <ChecklistItem label="Talked through what they wrote" item={feedback.checklists.duringCoding.talkedThroughCode} />
                                        <ChecklistItem label="Used meaningful variable names" item={feedback.checklists.duringCoding.meaningfulVariableNames} />
                                        <ChecklistItem label="Wrote modular/clean code" item={feedback.checklists.duringCoding.cleanModularCode} />
                                        <ChecklistItem label="Handled edge cases" item={feedback.checklists.duringCoding.handledEdgeCases} />
                                    </ul>
                                </div>

                                {/* After Coding */}
                                <div className="card p-5 bg-[oklch(0.12_0.02_260)]/50">
                                    <h3 className="font-[var(--font-display)] font-semibold text-xs uppercase tracking-wider mb-4 text-[oklch(0.6_0.05_250)]">
                                        After Coding
                                    </h3>
                                    <ul className="space-y-3">
                                        <ChecklistItem label="Walked through code with example" item={feedback.checklists.afterCoding.walkedThroughExample} />
                                        <ChecklistItem label="Tested edge cases manually" item={feedback.checklists.afterCoding.testedEdgeCasesManually} />
                                        <ChecklistItem label="Identified and fixed bugs" item={feedback.checklists.afterCoding.identifiedFixedBugs} />
                                        <ChecklistItem label="Discussed potential optimizations" item={feedback.checklists.afterCoding.discussedOptimizations} />
                                    </ul>
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4 justify-center pt-8 border-t border-[oklch(1_0_0/0.05)]">
                            <Link href="/interview/setup" className="btn-primary">
                                Practice Again
                            </Link>
                            <Link href="/" className="btn-secondary">
                                Back Home
                            </Link>
                        </div>
                    </div>
                </div>
            </main>
        );
    }

    // """""""""""""""""""""""""""""""""""""""""""""""
    // SESSION VIEW
    // """""""""""""""""""""""""""""""""""""""""""""""
    return (
        <main className="h-screen flex flex-col overflow-hidden">
            {/* Top Bar */}
            <header className="glass-strong flex items-center justify-between px-5 py-3 border-b border-[oklch(1_0_0/0.08)] shrink-0">
                <div className="flex items-center gap-3">
                    <span className="font-[var(--font-display)] font-bold gradient-text hidden sm:block">
                        InterviewerAI
                    </span>
                    <div className="flex gap-1.5">
                        <span className="text-xs px-2 py-0.5 rounded-full bg-[oklch(0.55_0.18_250/0.15)] text-[oklch(0.76_0.10_250)] border border-[oklch(0.55_0.18_250/0.3)]">
                            {session.config.difficulty.toUpperCase()}
                        </span>
                        <span className="text-xs px-2 py-0.5 rounded-full bg-[oklch(0.22_0.02_260)] text-[oklch(0.6_0.01_260)]">
                            {session.config.role}
                        </span>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    {/* Timer */}
                    <div
                        className={`font-mono text-sm px-3 py-1 rounded-lg ${timeWarning
                            ? 'bg-[oklch(0.75_0.18_85/0.15)] text-[oklch(0.75_0.18_85)] border border-[oklch(0.75_0.18_85/0.3)] animate-pulse'
                            : 'text-[oklch(0.6_0.01_260)]'
                            }`}
                    >
                        ⏱ {formatTime(elapsedSeconds)}{' '}
                        <span className="text-[oklch(0.4_0.01_260)]">
                            / {session.config.durationMinutes}:00
                        </span>
                    </div>
                    <button
                        onClick={handleEndInterview}
                        className="btn-secondary text-xs py-1.5 px-3 border-[oklch(0.63_0.22_25/0.3)] text-[oklch(0.63_0.22_25)] hover:bg-[oklch(0.63_0.22_25/0.1)]"
                    >
                        End Interview
                    </button>
                </div>
            </header>

            {/* Two-Panel Layout */}
            <div className="flex-1 grid grid-cols-1 lg:grid-cols-[380px_1fr] overflow-hidden">
                {/*  Left: Avatar + Chat  */}
                <div className="flex flex-col border-r border-[oklch(1_0_0/0.06)] overflow-hidden">
                    <AvatarPanel isSpeaking={isSpeaking} isThinking={isThinking} />


                    {/* Messages */}
                    <div className="flex-1 overflow-y-auto px-4 py-3 space-y-3">
                        {session.messages.map((msg: Message) => (
                            <div
                                key={msg.id}
                                className={`flex ${msg.role === 'candidate' ? 'justify-end' : 'justify-start'
                                    }`}
                            >
                                <div
                                    className={`max-w-[88%] px-3.5 py-2.5 rounded-2xl text-sm leading-relaxed ${msg.role === 'candidate'
                                        ? 'bg-[oklch(0.55_0.18_250)] text-white rounded-br-sm'
                                        : msg.type === 'hint'
                                            ? 'bg-[oklch(0.22_0.08_85/0.3)] text-[oklch(0.80_0.01_260)] border border-[oklch(0.75_0.18_85/0.2)] rounded-bl-sm'
                                            : 'bg-[oklch(0.22_0.02_260)] text-[oklch(0.85_0.01_260)] rounded-bl-sm'
                                        }`}
                                >
                                    {msg.type === 'hint' && (
                                        <div className="text-xs text-[oklch(0.75_0.18_85)] font-medium mb-1">
                                            Hint
                                        </div>
                                    )}
                                    {msg.content}
                                </div>
                            </div>
                        ))}

                        {/* Streaming text */}
                        {streamingText && (
                            <div className="flex justify-start">
                                <div className="max-w-[88%] px-3.5 py-2.5 rounded-2xl rounded-bl-sm text-sm leading-relaxed bg-[oklch(0.22_0.02_260)] text-[oklch(0.85_0.01_260)]">
                                    {streamingText}
                                    <span className="typewriter-cursor" />
                                </div>
                            </div>
                        )}

                        {/* Thinking dots */}
                        {isThinking && !streamingText && (
                            <div className="flex justify-start">
                                <div className="px-4 py-3 rounded-2xl rounded-bl-sm bg-[oklch(0.22_0.02_260)]">
                                    <div className="flex gap-1">
                                        {[0, 1, 2].map((i) => (
                                            <div
                                                key={i}
                                                className="w-2 h-2 rounded-full bg-[oklch(0.5_0.01_260)] animate-bounce"
                                                style={{ animationDelay: `${i * 0.15}s` }}
                                            />
                                        ))}
                                    </div>
                                </div>
                            </div>
                        )}

                        <div ref={chatEndRef} />
                    </div>

                    {/* Input Area */}
                    <div className="px-4 py-3 border-t border-[oklch(1_0_0/0.06)] space-y-2">
                        {/* Hint row */}
                        <div className="flex items-center gap-2">
                            <button
                                onClick={handleHint}
                                disabled={isRequestingHint || isThinking || !session.currentProblem}
                                className="text-xs px-3 py-1.5 rounded-lg bg-[oklch(0.22_0.08_85/0.3)] text-[oklch(0.75_0.18_85)] border border-[oklch(0.75_0.18_85/0.3)] hover:bg-[oklch(0.22_0.08_85/0.5)] transition-all disabled:opacity-40 disabled:cursor-not-allowed"
                                title="Ask for a hint without revealing the answer"
                            >
                                {isRequestingHint ? '⏳ Getting hint...' : '💡 I\'m stuck'}
                            </button>
                            <span className="text-xs text-[oklch(0.4_0.01_260)]">Ask for a nudge without spoiling the answer</span>
                        </div>

                        {/* Voice recording overlay — shown instead of the text box while listening */}
                        {isListening ? (
                            <div className="flex items-center gap-3">
                                {/* Mic stop button */}
                                {speechSupported && (
                                    <button
                                        onClick={toggleListening}
                                        className="shrink-0 w-10 h-10 rounded-xl flex items-center justify-center transition-all bg-[oklch(0.63_0.22_25)] animate-pulse"
                                        title="Stop recording (Space)"
                                    >
                                        ⏹
                                    </button>
                                )}
                                {/* Live transcript pill */}
                                <div className="flex-1 min-h-[40px] rounded-xl bg-[oklch(0.18_0.02_260)] border border-[oklch(0.63_0.22_25/0.5)] px-4 py-2 flex items-center">
                                    <span className="text-sm text-[oklch(0.75_0.01_260)] italic leading-snug">
                                        {interimTranscript
                                            ? `"${interimTranscript}…"`
                                            : <span className="text-[oklch(0.4_0.01_260)]">Listening… speak now</span>
                                        }
                                    </span>
                                </div>
                                {/* Ctrl+Space hint */}
                                <span className="text-[10px] text-[oklch(0.35_0.01_260)] shrink-0">Ctrl+Space<br />to stop</span>
                            </div>
                        ) : (
                            /* Normal typed-input row */
                            <div className="flex gap-2">
                                {speechSupported && (
                                    <button
                                        onClick={toggleListening}
                                        className="shrink-0 w-10 h-10 rounded-xl flex items-center justify-center transition-all bg-[oklch(0.22_0.02_260)] hover:bg-[oklch(0.28_0.02_260)]"
                                        title="Start speaking (Space)"
                                    >
                                        🎙
                                    </button>
                                )}
                                <input
                                    type="text"
                                    value={candidateInput}
                                    onChange={(e) => setCandidateInput(e.target.value)}
                                    onKeyDown={(e) =>
                                        e.key === 'Enter' && !e.shiftKey && handleSend()
                                    }
                                    placeholder="Type a response, or press Space to speak…"
                                    className="input-field flex-1 py-2 text-sm"
                                />
                                <button
                                    onClick={() => handleSend()}
                                    disabled={!candidateInput.trim() || isThinking}
                                    className="btn-primary px-4 py-2 text-sm shrink-0 disabled:opacity-40"
                                >
                                    Send
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                {/*  Right: Problem + Code Editor  */}
                <div className="flex flex-col overflow-hidden">
                    {/* Problem Panel */}
                    {(typedProblem || session.currentProblem) && (
                        <div className="flex flex-col border-b border-[oklch(1_0_0/0.06)] max-h-[42%] overflow-hidden">
                            {/* Problem header */}
                            <div className="flex items-center gap-3 px-4 py-2.5 border-b border-[oklch(1_0_0/0.04)] shrink-0">
                                <span className="text-xs px-2 py-0.5 rounded bg-[oklch(0.22_0.02_260)] font-mono text-[oklch(0.72_0.17_165)]">
                                    {session.config.language}
                                </span>
                                <h3 className="font-[var(--font-display)] font-semibold text-sm truncate">
                                    {session.currentProblem?.title || 'Loading problem...'}
                                </h3>
                                {session.currentProblem?.difficulty && (
                                    <span
                                        className={`text-xs ml-auto shrink-0 ${session.currentProblem.difficulty === 'easy'
                                            ? 'text-[oklch(0.72_0.17_165)]'
                                            : session.currentProblem.difficulty === 'medium'
                                                ? 'text-[oklch(0.75_0.18_85)]'
                                                : 'text-[oklch(0.63_0.22_25)]'
                                            }`}
                                    >
                                        {'• '}
                                        {session.currentProblem.difficulty.charAt(0).toUpperCase() +
                                            session.currentProblem.difficulty.slice(1)}
                                    </span>
                                )}
                            </div>

                            {/* Problem body */}
                            <div className="flex-1 overflow-y-auto px-4 py-3">
                                <p className="text-sm text-[oklch(0.7_0.01_260)] leading-relaxed whitespace-pre-wrap mb-3">
                                    {typedProblem}
                                    {isTyping && <span className="typewriter-cursor" />}
                                </p>
                                {/* The Problem's Examples and Constraints are deliberately hidden from the UI so the candidate must ask the conversational AI for them */}
                            </div>
                        </div>
                    )}

                    {/* Monaco Editor */}
                    <div className="flex-1 min-h-0">
                        <MonacoEditor
                            height="100%"
                            language={LANG_MONACO[session.config.language] || 'python'}
                            theme="vs-dark"
                            value={code}
                            onChange={(v) => setCode(v || '')}
                            options={{
                                fontSize: 14,
                                fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
                                minimap: { enabled: false },
                                padding: { top: 12 },
                                scrollBeyondLastLine: false,
                                automaticLayout: true,
                                wordWrap: 'on',
                                tabSize: 4,
                                lineNumbers: 'on',
                                renderLineHighlight: 'line',
                                cursorBlinking: 'smooth',
                                bracketPairColorization: { enabled: true },
                                suggest: { preview: true },
                            }}
                        />
                    </div>

                    {/* Run Result */}
                    <RunResultPanel result={runResult} />

                    {/* Editor Actions */}
                    <div className="flex items-center justify-between px-4 py-2.5 border-t border-[oklch(1_0_0/0.06)] shrink-0">
                        <div className="flex gap-2">
                            <button
                                onClick={handleRunCode}
                                disabled={isRunning || !code.trim()}
                                className="btn-secondary text-xs py-1.5 px-3 disabled:opacity-40"
                            >
                                {isRunning ? '⏳ Running...' : ' Run Code'}
                            </button>
                            <button
                                onClick={() => {
                                    const starter =
                                        session.currentProblem?.starterCode?.[
                                        session.config.language
                                        ] || '';
                                    setCode(starter);
                                    setRunResult(null);
                                }}
                                className="btn-secondary text-xs py-1.5 px-3"
                            >
                                Reset
                            </button>
                        </div>
                        <button
                            onClick={handleSubmitCode}
                            disabled={isThinking || !code.trim()}
                            className="btn-primary text-xs py-1.5 px-4 disabled:opacity-40"
                        >
                            Submit Solution
                        </button>
                    </div>
                </div>
            </div>
        </main>
    );
}

