/* ──────────────────────────────────────────────────────
   DASHBOARD OVERVIEW (logged in)
────────────────────────────────────────────────────── */

interface RecentSession {
  id: string;
  type: 'technical' | 'behavioral';
  config: Record<string, unknown>;
  created_at: string;
  duration_secs: number | null;
  feedback: { overall_score: number; decision: string } | null;
}

const DECISION_COLOR: Record<string, string> = {
  'Strong Hire': 'oklch(0.72_0.17_165)',
  'Hire': 'oklch(0.65_0.14_165)',
  'No Hire': 'oklch(0.63_0.22_25)',
};

function formatDate(iso: string) {
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

function DashboardHome({ user }: { user: User }) {
  const [recentSessions, setRecentSessions] = useState<RecentSession[]>([]);
  const [stats, setStats] = useState({ total: 0, avgScore: 0, hireRate: 0 });
  const supabase = createSupabaseBrowserClient();

  useEffect(() => {
    async function load() {
      const { data } = await supabase
        .from('sessions')
        .select('id, type, config, created_at, duration_secs, feedback(overall_score, decision)')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false })
        .limit(20);

      if (!data) return;

      const sessions = data as unknown as RecentSession[];
      setRecentSessions(sessions.slice(0, 5));

      const total = sessions.length;
      const withFeedback = sessions.filter((s) => s.feedback);
      const avgScore = withFeedback.length
        ? withFeedback.reduce((sum, s) => sum + (s.feedback?.overall_score ?? 0), 0) / withFeedback.length
        : 0;
      const hires = withFeedback.filter((s) =>
        s.feedback?.decision === 'Hire' || s.feedback?.decision === 'Strong Hire'
      ).length;
      setStats({ total, avgScore, hireRate: withFeedback.length ? Math.round((hires / withFeedback.length) * 100) : 0 });
    }
    load();
  }, [supabase, user.id]);

  const firstName = user.email?.split('@')[0] ?? 'there';

  return (
    <div className="px-6 py-8 max-w-4xl mx-auto space-y-10">
      {/* Greeting */}
      <div>
        <h1 className="font-[var(--font-display)] text-3xl font-bold mb-1">
          Hey, <span className="gradient-text">{firstName}</span> 👋
        </h1>
        <p className="text-[oklch(0.5_0.01_260)] text-sm">Ready to practice? Pick a mode below.</p>
      </div>

      {/* Quick-start cards */}
      <div className="grid sm:grid-cols-2 gap-5">
        <Link href="/interview/setup" className="card group p-6 flex gap-5 items-start hover:border-[oklch(0.55_0.18_250/0.5)] transition-all">
          <span className="text-4xl">💻</span>
          <div>
            <h2 className="font-[var(--font-display)] font-semibold text-lg mb-1 group-hover:text-[oklch(0.76_0.10_250)] transition-colors">Technical Interview</h2>
            <p className="text-sm text-[oklch(0.5_0.01_260)]">LeetCode-style problems with a live code editor, adaptive follow-ups, and detailed feedback.</p>
          </div>
        </Link>
        <Link href="/behavioral/setup" className="card group p-6 flex gap-5 items-start hover:border-[oklch(0.55_0.18_250/0.5)] transition-all">
          <span className="text-4xl">🗣️</span>
          <div>
            <h2 className="font-[var(--font-display)] font-semibold text-lg mb-1 group-hover:text-[oklch(0.76_0.10_250)] transition-colors">Behavioral Interview</h2>
            <p className="text-sm text-[oklch(0.5_0.01_260)]">Resume grill, STAR-format behavioral, or a mixed mode. Evidence-backed scoring.</p>
          </div>
        </Link>
      </div>

      {/* Stats row */}
      {stats.total > 0 && (
        <div className="grid grid-cols-3 gap-4">
          {[
            { label: 'Sessions', value: stats.total },
            { label: 'Avg Score', value: stats.avgScore ? `${stats.avgScore.toFixed(1)}/10` : '—' },
            { label: 'Hire Rate', value: stats.hireRate ? `${stats.hireRate}%` : '—' },
          ].map((s) => (
            <div key={s.label} className="card p-4 text-center">
              <div className="text-2xl font-bold gradient-text">{s.value}</div>
              <div className="text-[10px] uppercase tracking-wider text-[oklch(0.5_0.01_260)] mt-1">{s.label}</div>
            </div>
          ))}
        </div>
      )}

      {/* Recent sessions */}
      {recentSessions.length > 0 && (
        <div>
          <div className="flex items-center justify-between mb-4">
            <h2 className="font-[var(--font-display)] font-semibold text-lg">Recent Sessions</h2>
            <Link href="/dashboard" className="text-xs text-[oklch(0.5_0.01_260)] hover:text-[oklch(0.7_0.01_260)] transition-colors">View all →</Link>
          </div>
          <div className="space-y-2">
            {recentSessions.map((s) => {
              const decision = s.feedback?.decision;
              const color = decision ? DECISION_COLOR[decision] ?? '' : '';
              const cfg = s.config as { mode?: string; role?: string };
              return (
                <Link key={s.id} href={`/dashboard/${s.id}`} className="card px-5 py-3.5 flex items-center gap-4 hover:border-[oklch(1_0_0/0.15)] transition-all">
                  <span className="text-xl shrink-0">{s.type === 'technical' ? '💻' : '🗣️'}</span>
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-medium text-[oklch(0.75_0.01_260)] truncate">
                      {s.type === 'technical' ? 'Technical' : `Behavioral — ${cfg.mode?.replace('_', ' ')}`}
                      {cfg.role && <span className="ml-2 text-[oklch(0.45_0.01_260)]">· {cfg.role}</span>}
                    </div>
                    <div className="text-xs text-[oklch(0.4_0.01_260)] mt-0.5">{formatDate(s.created_at)}</div>
                  </div>
                  {s.feedback && (
                    <div className="shrink-0 text-right">
                      <span className="text-sm font-bold text-[oklch(0.8_0.01_260)]">{s.feedback.overall_score}/10</span>
                      <div className="text-[10px] font-semibold" style={{ color }}>{decision}</div>
                    </div>
                  )}
                  <span className="text-[oklch(0.3_0.01_260)] shrink-0">→</span>
                </Link>
              );
            })}
          </div>
        </div>
      )}

      {/* Empty state */}
      {stats.total === 0 && (
        <div className="card p-10 text-center space-y-3">
          <div className="text-4xl">🎤</div>
          <h3 className="font-[var(--font-display)] font-semibold text-lg">No sessions yet</h3>
          <p className="text-sm text-[oklch(0.5_0.01_260)]">Pick a mode above to start your first interview.</p>
        </div>
      )}
    </div>
  );
}

/* ──────────────────────────────────────────────────────
   ROOT EXPORT — switches between marketing and dashboard
────────────────────────────────────────────────────── */

export default function HomePage() {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [mounted, setMounted] = useState(false);
  const supabase = createSupabaseBrowserClient();

  useEffect(() => {
    setMounted(true);
    supabase.auth.getUser().then(({ data: { user } }) => {
      setUser(user);
      setIsLoading(false);
    });
  }, [supabase]);

  if (isLoading) return null; // avoid flash

  if (!user) return <MarketingPage mounted={mounted} />;

  return <DashboardHome user={user} />;
}

'use client';

import { useCallback, useEffect, useRef, useState } from 'react';

// =====================================================
// useDIDAvatar — D-ID WebRTC Streaming Hook
//
// Manages the full lifecycle of a D-ID streaming session:
//   1. Creates stream → gets WebRTC offer from D-ID
//   2. Creates RTCPeerConnection → sets remote/local descriptions
//   3. Exchanges ICE candidates
//   4. Receives video/audio stream → attaches to <video> element
//   5. Exposes `speak(text)` to make the avatar talk
//
// D-ID API docs: https://docs.d-id.com/reference/createstream
// =====================================================

type AvatarStatus =
    | 'idle'
    | 'connecting'
    | 'connected'
    | 'speaking'
    | 'error'
    | 'disconnected';

interface DIDStreamData {
    id: string;
    session_id: string;
    offer: RTCSessionDescriptionInit;
    ice_servers: RTCIceServer[];
}

interface UseDIDAvatarOptions {
    onStatusChange?: (status: AvatarStatus) => void;
    onError?: (message: string) => void;
    /** If true, falls back to emoji avatar when D-ID key is not set */
    fallbackToEmoji?: boolean;
}

export function useDIDAvatar(options: UseDIDAvatarOptions = {}) {
    const { onStatusChange, onError, fallbackToEmoji = true } = options;

    const [status, setStatus] = useState<AvatarStatus>('idle');
    const [isAvailable, setIsAvailable] = useState(false);
    const [videoStream, setVideoStream] = useState<MediaStream | null>(null);

    const pcRef = useRef<RTCPeerConnection | null>(null);
    const streamIdRef = useRef<string | null>(null);
    const sessionIdRef = useRef<string | null>(null);
    const videoRef = useRef<HTMLVideoElement | null>(null);
    const isConnectingRef = useRef(false);

    const updateStatus = useCallback(
        (s: AvatarStatus) => {
            setStatus(s);
            onStatusChange?.(s);
        },
        [onStatusChange]
    );

    // ── Check if D-ID is configured ──
    const checkAvailability = useCallback(async () => {
        try {
            // Lightweight probe — just check if server responds
            const res = await fetch('/api/avatar/stream', { method: 'POST' });
            setIsAvailable(res.status !== 503); // 503 = not configured
        } catch {
            setIsAvailable(false);
        }
    }, []);

    // ── Connect WebRTC ──
    const connect = useCallback(async () => {
        if (isConnectingRef.current || status === 'connected') return;
        isConnectingRef.current = true;
        updateStatus('connecting');

        try {
            // 1. Create D-ID stream → receive WebRTC offer
            const createRes = await fetch('/api/avatar/stream', { method: 'POST' });
            if (!createRes.ok) {
                throw new Error('Failed to create D-ID stream');
            }
            const streamData: DIDStreamData = await createRes.json();
            streamIdRef.current = streamData.id;
            sessionIdRef.current = streamData.session_id;

            // 2. Create RTCPeerConnection with D-ID's ICE servers
            const pc = new RTCPeerConnection({ iceServers: streamData.ice_servers });
            pcRef.current = pc;

            // 3. Handle incoming video/audio stream
            pc.ontrack = (event) => {
                if (event.streams && event.streams[0]) {
                    setVideoStream(event.streams[0]);
                    if (videoRef.current) {
                        videoRef.current.srcObject = event.streams[0];
                    }
                    updateStatus('connected');
                }
            };

            // 4. Relay ICE candidates to D-ID
            pc.onicecandidate = async (event) => {
                if (!event.candidate || !streamIdRef.current || !sessionIdRef.current) return;
                try {
                    await fetch('/api/avatar/ice', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({
                            streamId: streamIdRef.current,
                            sessionId: sessionIdRef.current,
                            candidate: event.candidate.toJSON(),
                        }),
                    });
                } catch {
                    // Non-fatal — ICE failover handles this
                }
            };

            pc.onconnectionstatechange = () => {
                if (pc.connectionState === 'failed' || pc.connectionState === 'disconnected') {
                    updateStatus('disconnected');
                }
            };

            // 5. Set D-ID's offer as remote description
            await pc.setRemoteDescription(new RTCSessionDescription(streamData.offer));

            // 6. Create our answer
            const answer = await pc.createAnswer();
            await pc.setLocalDescription(answer);

            // 7. Send our answer to D-ID
            const sdpRes = await fetch('/api/avatar/sdp', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    streamId: streamIdRef.current,
                    sessionId: sessionIdRef.current,
                    answer: answer,
                }),
            });

            if (!sdpRes.ok) {
                throw new Error('SDP exchange failed');
            }

            // Connection established — status will update via ontrack
        } catch (err) {
            const msg = err instanceof Error ? err.message : 'Avatar connection failed';
            console.error('D-ID avatar error:', msg);
            updateStatus('error');
            onError?.(msg);
        } finally {
            isConnectingRef.current = false;
        }
    }, [status, updateStatus, onError]);

    // ── Make the avatar speak ──
    const speak = useCallback(async (text: string) => {
        if (!streamIdRef.current || !sessionIdRef.current) {
            console.warn('Avatar not connected — cannot speak');
            return false;
        }
        if (!text.trim()) return false;

        updateStatus('speaking');

        try {
            const res = await fetch('/api/avatar/speak', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    streamId: streamIdRef.current,
                    sessionId: sessionIdRef.current,
                    text,
                }),
            });

            if (!res.ok) {
                const err = await res.json().catch(() => ({}));
                console.error('D-ID speak error:', err);
                updateStatus('connected');
                return false;
            }

            // Status will return to 'connected' when clip ends
            // D-ID sends video to the peer connection automatically
            setTimeout(() => {
                if (status === 'speaking') updateStatus('connected');
            }, text.length * 80); // rough estimate

            return true;
        } catch (err) {
            updateStatus('connected');
            return false;
        }
    }, [status, updateStatus]);

    // ── Disconnect ──
    const disconnect = useCallback(async () => {
        if (streamIdRef.current) {
            try {
                await fetch('/api/avatar/stream', {
                    method: 'DELETE',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ streamId: streamIdRef.current }),
                });
            } catch {
                // best effort
            }
        }
        pcRef.current?.close();
        pcRef.current = null;
        streamIdRef.current = null;
        sessionIdRef.current = null;
        setVideoStream(null);
        updateStatus('disconnected');
    }, [updateStatus]);

    // ── Attach stream to video element ──
    const attachVideo = useCallback((el: HTMLVideoElement | null) => {
        videoRef.current = el;
        if (el && videoStream) {
            el.srcObject = videoStream;
        }
    }, [videoStream]);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            disconnect();
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    return {
        status,
        isAvailable,
        videoStream,
        connect,
        disconnect,
        speak,
        attachVideo,
        checkAvailability,
        isConnected: status === 'connected' || status === 'speaking',
    };
}

