'use client';

import { useCallback, useEffect, useRef, useState } from 'react';

// =====================================================
// useSpeechInput — Web Speech API Hook (Continuous Mode)
// Keeps listening until the user manually stops.
// Auto-restarts on browser-imposed timeouts/silence.
// Fires onStop(fullTranscript) when user clicks stop.
// =====================================================

interface SpeechInputOptions {
    language?: string;
    onInterim?: (text: string) => void;
    onFinal?: (text: string) => void;
    onStop?: (fullTranscript: string) => void;
    onError?: (error: string) => void;
}

interface SpeechInputState {
    isListening: boolean;
    isSupported: boolean;
    interimTranscript: string;
}

export function useSpeechInput({
    language = 'en-US',
    onInterim,
    onFinal,
    onStop,
    onError,
}: SpeechInputOptions = {}) {
    const recognitionRef = useRef<SpeechRecognition | null>(null);
    const manuallyStoppedRef = useRef(false);
    const accumulatedRef = useRef(''); // running full transcript for this session

    const [state, setState] = useState<SpeechInputState>({
        isListening: false,
        isSupported: false,
        interimTranscript: '',
    });

    // Check browser support
    useEffect(() => {
        const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
        if (SR) setState((s) => ({ ...s, isSupported: true }));
    }, []);

    // --- Core: build and start a recognition session ---
    const createAndStart = useCallback(() => {
        const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
        if (!SR) {
            onError?.('Speech recognition is not supported in this browser.');
            return;
        }

        if (recognitionRef.current) {
            try { recognitionRef.current.stop(); } catch { }
        }

        const r = new SR();
        r.lang = language;
        r.continuous = true;      // Don't stop on pauses
        r.interimResults = true;  // Show live transcription
        r.maxAlternatives = 1;

        r.onstart = () => {
            setState((s) => ({ ...s, isListening: true, interimTranscript: '' }));
        };

        r.onresult = (event: SpeechRecognitionEvent) => {
            let interim = '';
            for (let i = event.resultIndex; i < event.results.length; i++) {
                const t = event.results[i][0].transcript;
                if (event.results[i].isFinal) {
                    accumulatedRef.current = (accumulatedRef.current + ' ' + t).trim();
                    onFinal?.(t);
                } else {
                    interim += t;
                }
            }
            setState((s) => ({ ...s, interimTranscript: interim }));
            onInterim?.(interim);
        };

        r.onerror = (event: SpeechRecognitionErrorEvent) => {
            // 'no-speech' is expected during pauses in continuous mode — ignore it silently
            if (event.error === 'no-speech') return;
            const msgs: Record<string, string> = {
                'not-allowed': 'Microphone access denied. Please allow access.',
                'network': 'Network error. Check your connection.',
                'audio-capture': 'No microphone found.',
                'service-not-allowed': 'Speech service not available.',
            };
            onError?.(msgs[event.error] ?? `Speech error: ${event.error}`);
        };

        r.onend = () => {
            // If user manually stopped, fire onStop and clean up
            if (manuallyStoppedRef.current) {
                setState((s) => ({ ...s, isListening: false, interimTranscript: '' }));
                onStop?.(accumulatedRef.current);
                accumulatedRef.current = '';
                manuallyStoppedRef.current = false;
                return;
            }
            // Otherwise the browser timed out — auto-restart to keep listening
            try { r.start(); } catch { }
        };

        recognitionRef.current = r;
        r.start();
    }, [language, onInterim, onFinal, onStop, onError]);

    const startListening = useCallback(() => {
        manuallyStoppedRef.current = false;
        accumulatedRef.current = '';
        createAndStart();
    }, [createAndStart]);

    const stopListening = useCallback(() => {
        manuallyStoppedRef.current = true;
        if (recognitionRef.current) {
            try { recognitionRef.current.stop(); } catch { }
            recognitionRef.current = null;
        }
        // onStop is fired in the onend handler once the browser confirms it stopped
    }, []);

    const toggleListening = useCallback(() => {
        if (state.isListening) {
            stopListening();
        } else {
            startListening();
        }
    }, [state.isListening, startListening, stopListening]);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            manuallyStoppedRef.current = true;
            recognitionRef.current?.stop();
        };
    }, []);

    return {
        ...state,
        startListening,
        stopListening,
        toggleListening,
    };
}

'use client';

import { useCallback, useRef } from 'react';

// =====================================================
// useTTS — Text-to-Speech Hook
// Plays interviewer responses via ElevenLabs or
// falls back to browser Web Speech Synthesis
// speak() returns a Promise that resolves when audio ENDS
// so callers can await it properly.
// =====================================================

interface TTSOptions {
    onStart?: () => void;
    onEnd?: () => void;
    onError?: (error: string) => void;
}

export function useTTS(options: TTSOptions = {}) {
    const audioRef = useRef<HTMLAudioElement | null>(null);
    const utteranceRef = useRef<SpeechSynthesisUtterance | null>(null);
    // Keep latest options in a ref so callbacks always see up-to-date values
    const optionsRef = useRef(options);
    optionsRef.current = options;

    /**
     * Play audio from ElevenLabs TTS API.
     * Returns a Promise that resolves to true when playback ENDS,
     * or false if ElevenLabs is unavailable (caller should fall back).
     */
    const speakWithElevenLabs = useCallback(async (text: string): Promise<boolean> => {
        try {
            const res = await fetch('/api/speech/tts', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ text }),
            });

            if (!res.ok) return false;

            const blob = await res.blob();
            const url = URL.createObjectURL(blob);

            // Stop any current audio
            if (audioRef.current) {
                audioRef.current.pause();
                audioRef.current.src = '';
            }

            const audio = new Audio(url);
            audioRef.current = audio;

            return new Promise<boolean>((resolve) => {
                audio.onplay = () => optionsRef.current.onStart?.();
                audio.onended = () => {
                    URL.revokeObjectURL(url);
                    optionsRef.current.onEnd?.();
                    resolve(true);
                };
                audio.onerror = () => {
                    URL.revokeObjectURL(url);
                    optionsRef.current.onError?.('Audio playback failed');
                    resolve(false); // resolve false so caller falls back
                };
                audio.play().catch(() => resolve(false));
            });
        } catch {
            return false;
        }
    }, []);

    /**
     * Fall back to browser Web Speech Synthesis.
     * Returns a Promise that resolves when utterance ENDS.
     */
    const speakWithBrowser = useCallback((text: string): Promise<void> => {
        return new Promise((resolve) => {
            if (!('speechSynthesis' in window)) {
                optionsRef.current.onError?.('Text-to-speech not supported in this browser.');
                resolve();
                return;
            }

            // Cancel any ongoing speech
            window.speechSynthesis.cancel();

            const utterance = new SpeechSynthesisUtterance(text);
            utteranceRef.current = utterance;

            const voices = window.speechSynthesis.getVoices();
            const preferred = voices.find(
                (v) =>
                    v.name.includes('Samantha') ||
                    v.name.includes('Karen') ||
                    v.name.includes('Female') ||
                    (v.lang.startsWith('en') && v.name.includes('f'))
            );
            if (preferred) utterance.voice = preferred;

            utterance.rate = 0.95;
            utterance.pitch = 1.0;
            utterance.volume = 1.0;
            utterance.lang = 'en-US';

            utterance.onstart = () => optionsRef.current.onStart?.();
            utterance.onend = () => {
                optionsRef.current.onEnd?.();
                resolve();
            };
            utterance.onerror = (e) => {
                optionsRef.current.onError?.(e.error);
                resolve(); // resolve so callers don't hang
            };

            window.speechSynthesis.speak(utterance);
        });
    }, []);

    /**
     * Main speak function.
     * Tries ElevenLabs first, falls back to browser TTS.
     * Returns a Promise that resolves when speech ENDS.
     */
    const speak = useCallback(
        async (text: string): Promise<void> => {
            if (!text.trim()) return;
            const usedElevenLabs = await speakWithElevenLabs(text);
            if (!usedElevenLabs) {
                await speakWithBrowser(text);
            }
        },
        [speakWithElevenLabs, speakWithBrowser]
    );

    const stop = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.pause();
            audioRef.current.src = '';
        }
        window.speechSynthesis?.cancel();
    }, []);

    return { speak, stop };
}

// Web Speech API type declarations
// Fills gaps in TypeScript's DOM lib for the Speech Recognition API

// ─── Error event ───
interface SpeechRecognitionErrorEvent extends Event {
    readonly error: string;
    readonly message: string;
}

// ─── Result types ───
interface SpeechRecognitionAlternative {
    readonly transcript: string;
    readonly confidence: number;
}

interface SpeechRecognitionResult {
    readonly isFinal: boolean;
    readonly length: number;
    item(index: number): SpeechRecognitionAlternative;
    [index: number]: SpeechRecognitionAlternative;
}

interface SpeechRecognitionResultList {
    readonly length: number;
    item(index: number): SpeechRecognitionResult;
    [index: number]: SpeechRecognitionResult;
}

interface SpeechRecognitionEvent extends Event {
    readonly resultIndex: number;
    readonly results: SpeechRecognitionResultList;
}

// ─── Main recognition interface ───
interface SpeechRecognition extends EventTarget {
    lang: string;
    continuous: boolean;
    interimResults: boolean;
    maxAlternatives: number;

    onstart: ((this: SpeechRecognition, ev: Event) => void) | null;
    onend: ((this: SpeechRecognition, ev: Event) => void) | null;
    onerror: ((this: SpeechRecognition, ev: SpeechRecognitionErrorEvent) => void) | null;
    onresult: ((this: SpeechRecognition, ev: SpeechRecognitionEvent) => void) | null;

    start(): void;
    stop(): void;
    abort(): void;
}

declare var SpeechRecognition: {
    prototype: SpeechRecognition;
    new(): SpeechRecognition;
};

// ─── Window augmentation ───
interface Window {
    SpeechRecognition: typeof SpeechRecognition;
    webkitSpeechRecognition: typeof SpeechRecognition;
}
